INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 10, 0.5, "ナナカちゃんセレクトの伝説のスク水を\n完璧に着こなしておりますなあ！", 0, 903, 0, 113311, 1, 0, 19030018);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (91, "", "", "", "", 903, "", 0, "", "", 19030019);
