INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 10, 0.5, "なっ、これは他に持ってないから\n仕方なくだなあ…", 0, 903, 0, 113211, 1, 0, 19030023);
