INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 10, 0.5, "シズルさまにエリコさま、\nどうかされたのですか？", 0, 905, 0, 107611, 1, 0, 19050041);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (91, "", "", "", "", 905, "", 0, "", "", 19050042);
