INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (3, 0, "", "05_eriko_pressure_in", 1, 905, 0.1, 117011, "05_eriko_pressure_loop", 0.1, 19050049);
