INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 10, 0.5, "一人で食べつくしても心が痛まない、\n自己中心的な精神構造…", 0, 920, 0, 115711, 1, 0, 19200043);
