INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 10, 0.5, "ここメルクリゾートでは今、\n不可解な噂が流れている。", 0, 922, 0, 115711, 1, 0, 19220017);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (91, "", "", "", "", 922, "", 0, "", "", 19220018);
