INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 10, 0.5, "自身や知り合いと全く同じ姿をした\n人物に出会う…そんな噂だ。", 0, 922, 0, 115711, 1, 0, 19220021);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (91, "", "", "", "", 922, "", 0, "", "", 19220022);
