INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 10, 0.5, "似た人物はこの世に３人はいるというが\nその３人が偶然集まった？　いや…", 0, 922, 0, 115711, 1, 0, 19220033);
