INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 10, 0.5, "ここメルクリゾートではプールサイドで\nたい焼きを売る怪人の噂がある。", 0, 923, 0, 115711, 1, 0, 19230017);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (91, "", "", "", "", 923, "", 0, "", "", 19230018);
