INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 10, 0.5, "…濡れやすいプールエリアで売る\nなんて常人の思考では考えられない。", 0, 923, 0, 115711, 1, 0, 19230027);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (91, "", "", "", "", 923, "", 0, "", "", 19230028);
