INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 10, 0.5, "幻のたい焼き売りの姿を見ると\n幸せになれるだなんて話も聞いたよ。", 0, 923, 0, 115711, 1, 0, 19230039);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (91, "", "", "", "", 923, "", 0, "", "", 19230040);
