INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 6, 1, "はーっはっはっは！\nこうして水の上をたゆたっていると\nあの冒険を思い出すな！", 0, 942, 0, 113211, 1, 0, 19420019);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (91, "", "", 0, "", 942, "", 0, "", "", 19420020);
