INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 7, 1, "ええ、とても楽しい冒険でしたね。\nあの衣装は今でも\n大切に保管していますよ。", 0, 942, 0, 127111, 1, 0, 19420025);
