INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 7, 0.5, "あれからどうだ？\nなにか面白い事件や冒険があったなら\nぜひ聞かせてくれ！", 0, 942, 0, 113211, 1, 0, 19420031);
