INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (33, -125, "", -350, 12, 943, "", 1174114, 6.92307692307692, "", 19430028);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (21, "", "", "vo_fpc_30302", "", 943, "", "vo_fpc", 0, "", 19430029);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 6, 1, "そうだ、この流れに身を任せることで\n渓流の魚たちの気持ちを学べば、\n次の釣りに活かせるかもしれないな。", 0, 943, 0, 122511, 1, 0, 19430030);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (91, "", "", "", "", 943, "", 0, "", "", 19430031);
