INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 5, 0.5, "むっ…なんだ？\nこの獲物を狙う猛禽のような殺気は？\n誰かいるのか？", 0, 943, 0, 122511, 1, 0, 19430038);
