INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 10, 1, "あら、タマキさんじゃない。\nこんなところで何やってるの？", 0, 944, 0, 126811, 1, 0, 19440030);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (91, "", "", "", "", 944, "", 0, "", "", 19440031);
