INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 8, 0.5, "大丈夫にゃ。バレないように…\nってやばいにゃ！　見回りだにゃ！", 0, 944, 0, 107911, 1, 0, 19440046);
