INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (3, 1, "", "45_makoto_talk", "", 945, 0.1, 110411, "", "", 19450019);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (21, "", "", "vo_fpc_30501", "", 945, "", "vo_fpc", 0, "", 19450020);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 10, 1, "どうしたんだ、ユイ？\nあいつのために\nわざわざ弁当作ってきたんだろ？\nとっとと誘えばいいじゃないか。", 0, 945, 0, 110411, 1, 0, 19450021);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (91, "", "", "", "", 945, "", 0, "", "", 19450022);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (21, "", "", "vo_fpc_30502", "", 945, "", "vo_fpc", 0, "", 19450023);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 7, 1, "買い出しまで手伝ってもらったのに\nごめんね。でも、お弁当の中身、\nちょっと張り切りすぎちゃって…", 0, 945, 0, 122611, 1, 0, 19450024);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (91, "", "", "", "", 945, "", 0, "", "", 19450025);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (21, "", "", "vo_fpc_30503", "", 945, "", "vo_fpc", 0, "", 19450026);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 7, 1, "なんだよ、張り切りすぎちゃったって。\n用意してた材料は普通だったろ？\nん？　そういやあピンクの桜でんぶ\n買ってたよな。まさか…", 0, 945, 0, 110411, 1, 0, 19450027);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (91, "", "", "", "", 945, "", 0, "", "", 19450028);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (3, 0, "", "45_makoto_talk_surprise", 1, 945, 0.1, 110411, "45_makoto_talk_surprise_loop", 0.1, 19450029);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (3, 0, "", "45_yui_shy_in", 1, 945, 0.1, 122611, "45_yui_shy_loop", 0.1, 19450030);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (3, 0, "", "45_yui_shy_in", 1, 945, 0.1, 1, "45_yui_shy_loop", 0.1, 19450031);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (21, "", "", "vo_fpc_30504", "", 945, "", "vo_fpc", 0, "", 19450032);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 5, 1, "…うん、やっちゃった…\nおっきなハートマーク…\nやっぱりこれは無しで！\nマコトちゃん食べてくれる！？", 0, 945, 0, 122611, 1, 0, 19450033);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (91, "", "", "", "", 945, "", 0, "", "", 19450034);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (3, 1, "", "45_makoto_idle", "", 945, 0.1, 110411, "", "", 19450035);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (21, "", "", "vo_fpc_30505", "", 945, "", "vo_fpc", 0, "", 19450036);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 9, 0.5, "わかったよ。あたしがついてって\nかわりに食ってやるから…\n他のおかずは自信作なんだろ？\nほら、早く行くぞ！", 0, 945, 0, 110411, 1, 0, 19450037);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (91, "", "", "", "", 945, "", 0, "", "", 19450038);
